import { useAuth } from '../context/AuthContext';

function Navbar() {
  const { user, logout } = useAuth();

  return (
    <div className="navbar">
      <div className="logo">
        FlowDesk CRM
      </div>

      <div className="user-box">
        <div className="user-avatar">
          {user?.name?.charAt(0)}
        </div>

        <div>
          <h4>{user?.name}</h4>
          <p>{user?.role}</p>
        </div>

        <button
          className="logout-btn"
          onClick={logout}
        >
          Logout
        </button>
      </div>
    </div>
  );
}

export default Navbar;
